import React, { useEffect, useState, useMemo } from "react";
import { supabase } from "../supabaseClient";
import { 
    Navigation, LogOut, Search, RefreshCcw, 
    MessageCircle, MapPin, Clock, Calendar, 
    CheckCircle, XCircle, Send, Loader2, Car, Phone, 
    ShieldCheck, Zap, ArrowRight, User
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [timeFilter, setTimeFilter] = useState("all");
    const [statusFilter, setStatusFilter] = useState("all");

    useEffect(() => {
        fetchRides();
        const subscription = supabase.channel('command_center')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides())
            .subscribe();
        return () => supabase.removeChannel(subscription);
    }, []);

    const fetchRides = async () => {
        const { data, error } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (!error) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq(id, id);
        fetchRides();
    };

    const sendWhatsApp = (num, name, type) => {
        const cleanNum = num.replace(/\D/g, '');
        const msg = type === 'alt' ? `Emergency contact for ${name}.` : `Hi ${name}, PAHEL support here.`;
        window.open(`https://wa.me/91${cleanNum}?text=${encodeURIComponent(msg)}`, '_blank');
    };

    const stats = useMemo(() => {
        const todayStr = new Date().toLocaleDateString('en-CA');
        return {
            total: rides.length,
            pending: rides.filter(r => r.status === 'pending').length,
            todayActive: rides.filter(r => r.ride_date === todayStr).length,
            completedToday: rides.filter(r => r.status === 'completed' && r.ride_date === todayStr).length
        };
    }, [rides]);

    const filteredData = useMemo(() => {
        const todayStr = new Date().toLocaleDateString('en-CA');
        return rides.filter(r => {
            const timeMatch = timeFilter === 'all' || (timeFilter === 'today' && r.ride_date === todayStr);
            const statusMatch = statusFilter === 'all' || r.status === statusFilter;
            const s = search.toLowerCase();
            const searchMatch = r.passenger_name?.toLowerCase().includes(s) || r.phone_number?.includes(s);
            return timeMatch && statusMatch && searchMatch;
        });
    }, [rides, search, timeFilter, statusFilter]);

    if (loading) return (
        <div className="loader-container">
            <Loader2 className="spinning" size={48} color="var(--primary)" />
        </div>
    );

    return (
        <div className="app-container">
            <header className="dash-header">
                <div>
                    <h1>PAHEL Schedule Ride Panel</h1>
                    <p>Operational Live Feed • {filteredData.length} rides found</p>
                </div>
                <div style={{display: 'flex', gap: '12px'}}>
                    <button className="btn-icon" onClick={fetchRides} title="Refresh"><RefreshCcw size={18}/></button>
                    <button className="btn-icon" style={{background: 'var(--danger)', color: '#fff', border:'none'}} onClick={() => supabase.auth.signOut()}><LogOut size={18} /></button>
                </div>
            </header>

            <div className="stats-container">
                <div className="glass-card">
                    <span className="stat-label">Total Volume</span>
                    <span className="stat-value">{stats.total}</span>
                    <Zap className="stat-icon" />
                </div>
                <div className="glass-card" style={{borderLeft: '5px solid var(--warning)'}}>
                    <span className="stat-label">Pending Rides</span>
                    <span className="stat-value" style={{color: 'var(--warning)'}}>{stats.pending}</span>
                    <Clock className="stat-icon" />
                </div>
                <div className="glass-card" style={{borderLeft: '5px solid var(--primary)'}}>
                    <span className="stat-label">Scheduled Today</span>
                    <span className="stat-value" style={{color: 'var(--primary)'}}>{stats.todayActive}</span>
                    <Calendar className="stat-icon" />
                </div>
                <div className="glass-card" style={{borderLeft: '5px solid var(--success)'}}>
                    <span className="stat-label">Successful Rides</span>
                    <span className="stat-value" style={{color: 'var(--success)'}}>{stats.completedToday}</span>
                    <ShieldCheck className="stat-icon" />
                </div>
            </div>

            <div className="filter-engine">
                <div className="search-wrapper">
                    <Search size={18} style={{position: 'absolute', left: '16px', top: '14px', color: 'var(--text-muted)'}} />
                    <input placeholder="Search name or phone..." onChange={(e) => setSearch(e.target.value)} />
                </div>

                <div className="filter-tabs">
                    {['all', 'today'].map(t => (
                        <button key={t} onClick={() => setTimeFilter(t)} className={`tab ${timeFilter === t ? 'active' : ''}`}>{t.toUpperCase()}</button>
                    ))}
                </div>

                <div className="status-select-box">
                    <select onChange={(e) => setStatusFilter(e.target.value)}>
                        <option value="all">All Status</option>
                        <option value="pending">Pending</option>
                        <option value="confirmed">Confirmed</option>
                        <option value="completed">Completed</option>
                    </select>
                </div>
            </div>

            <div className="table-wrapper">
                <table className="pahel-table">
                    <thead>
                        <tr>
                            <th>Passenger & Vehicle</th>
                            <th>Contact Hub</th>
                            <th>Route Mapping</th>
                            <th>Schedule</th>
                            <th>Current Status</th>
                            <th style={{textAlign:'right'}}>Operations</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredData.map(ride => (
                            <tr key={ride.id}>
                                <td>
                                    <div style={{fontWeight: 800, fontSize: '15px', display:'flex', alignItems:'center', gap: '8px'}}>
                                        <User size={16} color="var(--primary)"/> {ride.passenger_name}
                                    </div>
                                    <div style={{marginTop: '8px'}}><span className="vehicle-badge"><Car size={14}/> {ride.vehicle_class || 'Standard'}</span></div>
                                </td>
                                <td>
                                    <button onClick={() => sendWhatsApp(ride.phone_number, ride.passenger_name, 'main')} className="contact-btn wa-main" style={{border:'none', cursor:'pointer'}}>
                                        <MessageCircle size={14}/> WhatsApp
                                    </button>
                                </td>
                                <td>
                                    <div style={{fontSize: '13px', color: 'var(--success)', fontWeight: 700}}>{ride.pickup_location}</div>
                                    <ArrowRight size={12} style={{margin: '4px 10px', color: 'var(--text-muted)'}} />
                                    <div style={{fontSize: '13px', color: 'var(--danger)', fontWeight: 700}}>{ride.drop_location}</div>
                                </td>
                                <td>
                                    <div style={{fontWeight: 700}}>{ride.ride_date}</div>
                                    <div style={{fontSize:'12px', color:'var(--text-muted)'}}>{ride.ride_time}</div>
                                </td>
                                <td><span className={`status-pill ${ride.status}`}>{ride.status}</span></td>
                                <td>
                                    <div className="action-btn-group">
                                        <button className="op-btn" onClick={() => updateStatus(ride.id, 'confirmed')}>
                                            <Send size={14} color="var(--primary)"/> Confirm Ride
                                        </button>
                                        <button className="op-btn" onClick={() => updateStatus(ride.id, 'completed')}>
                                            <CheckCircle size={14} color="var(--success)"/> Complete
                                        </button>
                                        <button className="op-btn" onClick={() => updateStatus(ride.id, 'cancelled')}>
                                            <XCircle size={14} color="var(--danger)"/> Cancel
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            <style>{`.spinning { animation: spin 1s linear infinite; } @keyframes spin { 100% { transform: rotate(360deg); } }`}</style>
        </div>
    );
};

export default Dashboard;
